// video playlist — plays 0 → 1 → 2, then loops from 0
var vids = [
  '/dist/media/td_render_2.mp4',
  '/dist/media/td_render_1.mp4',
  '/dist/media/td_render_0.mp4'
];
var vidIdx = 0;

function playVid(idx) {
  var vid = document.createElement('video');
  vid.crossOrigin = 'anonymous';
  vid.autoplay = true;
  vid.loop = false;
  vid.muted = true;
  vid.src = vids[idx];
  vid.addEventListener('loadeddata', ()=> {
    s0.src = vid;
    s0.tex = s0.regl.texture({ data: vid });
    s0.dynamic = true;
    vid.play();
  });
  vid.addEventListener('ended', ()=> {
    vidIdx = (vidIdx + 1) % vids.length;
    playVid(vidIdx);
  });
}
playVid(0);

